#include <stdio.h>
#include <stdint.h>
#include <inttypes.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t N,M,K; scanf("%" PRId64 " %" PRId64 " %" PRId64, &N,&M,&K);
        __int128 total = (__int128)N * M;
        __int128 X = total - K;
        if (X < 0){
            puts("NO");
            continue;
        }
        if (X == 0){
            puts("YES");
            continue;
        }
        int64_t x = (int64_t)X; // X fits in 64‑bit because N,M ≤1e9, K ≤1e18
        int64_t limit = (int64_t)sqrt((long double)x);
        int found = 0;
        for(int64_t d=1; d<=limit && !found; ++d){
            if(x % d) continue;
            int64_t a = d;
            int64_t b = x / d;
            if(a <= N && b <= M) found = 1;
            else if(b <= N && a <= M) found = 1;
        }
        puts(found?"YES":"NO");
    }
    return 0;
}

