import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            long N = fs.nextLong();
            long M = fs.nextLong();
            long K = fs.nextLong();
            java.math.BigInteger total = java.math.BigInteger.valueOf(N).multiply(java.math.BigInteger.valueOf(M));
            java.math.BigInteger Xbig = total.subtract(java.math.BigInteger.valueOf(K));
            if (Xbig.signum() < 0) { sb.append("NO\n"); continue; }
            if (Xbig.equals(java.math.BigInteger.ZERO)) { sb.append("YES\n"); continue; }
            long X = Xbig.longValue(); // fits because N,M ≤1e9
            long limit = (long)Math.sqrt((double)X);
            boolean ok = false;
            for (long d = 1; d <= limit && !ok; ++d) {
                if (X % d != 0) continue;
                long a = d, b = X / d;
                if (a <= N && b <= M) ok = true;
                else if (b <= N && a <= M) ok = true;
            }
            sb.append(ok ? "YES" : "NO").append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for Java
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false; if (c=='-'){ neg=true; c=readByte(); }
            long val = 0; while (c > ' ') { val = val*10 + (c-'0'); c = readByte(); }
            return neg? -val : val; }
        int nextInt() throws IOException { return (int)nextLong(); }
    }
}

