#!/usr/bin/env python3
import sys, math

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); K = int(next(it))
        total = N * M
        X = total - K
        if X < 0:
            out.append("NO")
            continue
        if X == 0:
            out.append("YES")
            continue
        limit = int(math.isqrt(X))
        ok = False
        for d in range(1, limit+1):
            if X % d:
                continue
            a, b = d, X // d
            if a <= N and b <= M:
                ok = True
                break
            if b <= N and a <= M:
                ok = True
                break
        out.append("YES" if ok else "NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

